const buildFixtureTrace = (
  liveCase: LiveCase,
  sessionId: string,
): { readonly path: string; readonly content: string } => {
  const path = join(TRACE_DIR, sessionId, `${liveCase.id}.ndjson`);
  const fixturePath =
    liveCase.contrastLabel === "aggressive-fixture"
      ? join(ROOT_DIR, "src", "director", "prompt", "fixtures", "aggressive-phase24-bot-1.ndjson")
      : liveCase.contrastLabel === "cautious-fixture"
        ? join(ROOT_DIR, "src", "director", "prompt", "fixtures", "cautious-phase24-bot-1.ndjson")
        : null;
  const content =
    fixturePath === null
      ? runBot(
          liveCase.policy,
          liveCase.traceSeed,
          createFallbackFloorContentProvider(),
          220,
          {
            createdAt: CREATED_AT,
            runId: `${sessionId}-${liveCase.id}-trace`,
            writer: memoryTraceWriter(path),
          },
        ).trace.content
      : readFileSync(fixturePath, "utf8");

  writeText(path, content);

  return { path, content };
};

